type KeywordDefinition = Record<
  string,
  | {
      keyword: string | string[];
      needsFilterKey?: boolean;
      leading?: string[];
      trailing?: string[];
    }
  | undefined
>;

/** @internal */
export const filterFieldKeywords: KeywordDefinition = {
  '=': { keyword: ['=', '=*', '= *'], needsFilterKey: true },
  '~': { keyword: '~', needsFilterKey: true },
  '<': { keyword: ['<', '<='], needsFilterKey: true },
  '>': { keyword: ['>', '>='], needsFilterKey: true },
  '!': { keyword: ['!=', '!~', '!=*', '!= *'], needsFilterKey: true },
  a: { keyword: 'and', leading: [' ', '(', ')'], trailing: [' ', '(', ')'] },
  o: { keyword: 'or', leading: [' ', '(', ')'], trailing: [' ', '(', ')'] },
  i: {
    keyword: 'in',
    needsFilterKey: true,
    leading: [' '],
    trailing: [' (', '('],
  },
  n: { keyword: 'not in', needsFilterKey: true, trailing: [' (', '('] },
  '*': { keyword: ['*~', '* ~'] },
  $: { keyword: ['$.', '$['], needsFilterKey: true },
};
